JS_EXTRA = [
  ("Design Patterns","Module pattern","Intermediate","Encapsulate code and expose public API","What is the revealing module pattern?","Define everything privately, return an object exposing only public parts. Predecessor to ES modules.","const Counter = (() => {\n  let count = 0; // private\n  const increment = () => ++count;\n  const reset = () => { count = 0; };\n  return { increment, reset, getCount: () => count }; // public\n})();\nCounter.increment(); Counter.increment();\nCounter.getCount(); // 2"),
  ("Design Patterns","Observer pattern","Advanced","Pub/Sub — decouple emitters from listeners","How does EventEmitter implement Observer?","Maintains a map of event→listeners. emit iterates and calls each. on/off add/remove. Node.js, React Native DeviceEventEmitter, and browser EventTarget all use this pattern.","class EventEmitter {\n  #events = new Map();\n  on(event, fn) {\n    (this.#events.get(event) ?? this.#events.set(event, []).get(event)).push(fn);\n    return () => this.off(event, fn);\n  }\n  off(event, fn) { this.#events.set(event, (this.#events.get(event) ?? []).filter(f => f !== fn)); }\n  emit(event, ...args) { (this.#events.get(event) ?? []).forEach(fn => fn(...args)); }\n}"),
  ("Design Patterns","Factory pattern","Intermediate","Create objects without specifying exact class","When to use Factory over constructor?","When creation logic is complex, when subclass to create depends on input, or when you want to hide implementation details.","function createUser(role) {\n  const base = { id: crypto.randomUUID(), role };\n  switch (role) {\n    case 'admin': return { ...base, permissions: ['read','write','delete'], level: 'high' };\n    case 'editor': return { ...base, permissions: ['read','write'], level: 'mid' };\n    default: return { ...base, permissions: ['read'], level: 'low' };\n  }\n}"),
  ("Design Patterns","Singleton pattern","Intermediate","One instance per application","Is Singleton an antipattern?","Often yes — creates hidden global state, makes testing hard (shared state between tests). Acceptable for: logger, DB connection pool, config object. Use dependency injection instead where possible.","class Database {\n  static #instance = null;\n  #connection;\n  static getInstance() {\n    Database.#instance ??= new Database();\n    return Database.#instance;\n  }\n  connect(url) { this.#connection = createConnection(url); }\n}\n// Always same instance\nDatabase.getInstance() === Database.getInstance(); // true"),
  ("Design Patterns","Strategy pattern","Advanced","Select algorithm at runtime","Real-world JS example of Strategy?","Sorting strategies, payment processors, authentication methods, validation rules.","const validators = {\n  email: v => /^[^@]+@[^@]+$/.test(v),\n  phone: v => /^\\d{10}$/.test(v),\n  username: v => v.length >= 3 && /^[a-z0-9_]+$/i.test(v),\n};\nfunction validate(value, strategy) {\n  const fn = validators[strategy];\n  if (!fn) throw new Error(`Unknown strategy: ${strategy}`);\n  return fn(value);\n}\nvalidate('test@mail.com', 'email'); // true"),
  ("Functional","Pure functions & immutability","Intermediate","No side effects, same input → same output","Why prefer immutability in JS?","Predictability, easier debugging, enables time-travel debugging, React/Redux state comparison (===) works correctly, prevents shared mutable state bugs.","// Mutable -- bad\nconst addItem = (arr, item) => { arr.push(item); return arr; };\n// Immutable -- good\nconst addItem = (arr, item) => [...arr, item];\nconst updateUser = (user, changes) => ({ ...user, ...changes });\nconst removeById = (arr, id) => arr.filter(x => x.id !== id);"),
  ("Functional","Composition & pipe","Advanced","Combine functions: output of one feeds next","What is the difference between compose and pipe?","compose: right-to-left (mathematical). pipe: left-to-right (more readable for data transformation pipelines).","const pipe = (...fns) => x => fns.reduce((v, f) => f(v), x);\nconst compose = (...fns) => x => fns.reduceRight((v, f) => f(v), x);\n\nconst processUser = pipe(\n  user => ({ ...user, name: user.name.trim() }),\n  user => ({ ...user, email: user.email.toLowerCase() }),\n  user => ({ ...user, slug: user.name.replace(/\\s+/g, '-') }),\n);\nprocessUser({ name: ' Alice ', email: 'ALICE@MAIL.COM' });"),
  ("Browser APIs","Web Workers","Advanced","Run JS in background thread — no DOM access","What data can you NOT pass to a Web Worker?","Functions, DOM nodes, class instances with methods. Transferable objects (ArrayBuffer, OffscreenCanvas) are transferred (moved, not copied) — the original is neutered.","// worker.js\nself.onmessage = ({ data }) => {\n  const result = expensiveCalculation(data);\n  self.postMessage(result);\n};\n// main.js\nconst worker = new Worker('worker.js');\nworker.postMessage(largeArray);\nworker.onmessage = ({ data }) => setResults(data);\nworker.terminate(); // clean up"),
  ("Browser APIs","WebSockets","Intermediate","Full-duplex real-time communication","What is the difference between WebSocket and Server-Sent Events?","WebSocket: bidirectional, binary + text, must manage reconnection. SSE: unidirectional (server→client only), text only, auto-reconnects, simpler. Use SSE for live feeds; WebSocket for chat/games.","const ws = new WebSocket('wss://api.devquiz.app/ws');\nws.onopen    = () => ws.send(JSON.stringify({ type: 'subscribe', channel: 'quiz' }));\nws.onmessage = ({ data }) => dispatch(handleMessage(JSON.parse(data)));\nws.onerror   = (err) => console.error('WS error', err);\nws.onclose   = () => setTimeout(reconnect, 1000); // auto-reconnect"),
  ("Browser APIs","Service Workers","Advanced","Proxy between browser and network — enables PWA","What is the lifecycle of a Service Worker?","Install → Activate → Fetch intercept. New SW waits in 'waiting' state while old SW controls open pages. skipWaiting() + clients.claim() force immediate takeover.","// sw.js\nconst CACHE = 'v1';\nself.addEventListener('install', e => {\n  e.waitUntil(caches.open(CACHE).then(c => c.addAll(['/','index.html','app.js'])));\n});\nself.addEventListener('fetch', e => {\n  e.respondWith(\n    caches.match(e.request).then(cached => cached ?? fetch(e.request))\n  );\n});"),
  ("Performance","JS Performance","Advanced","Profiling, memory, rendering optimization","What causes memory leaks in browser JS?","Detached DOM nodes held in closures, forgotten event listeners, setInterval not cleared, cache with no eviction, WeakRef alternatives not used.","// Profile with Performance API\nperformance.mark('start');\nheavyOperation();\nperformance.mark('end');\nperformance.measure('heavy', 'start', 'end');\nconsole.log(performance.getEntriesByName('heavy')[0].duration);\n// Avoid: memory leak from detached node\nlet el = document.getElementById('btn');\nconst handler = () => {};\nel.addEventListener('click', handler);\n// FIX: remove listener before removing element\nel.removeEventListener('click', handler);"),
  ("Security","XSS & Injection","Tricky","Cross-site scripting and injection attacks","How do you prevent XSS in vanilla JS?","Never use innerHTML/dangerouslySetInnerHTML with user input. Use textContent for plain text. Sanitize with DOMPurify if HTML is needed. Set CSP headers.","// VULNERABLE\nelement.innerHTML = userInput;\n// SAFE\nelement.textContent = userInput;\n// If HTML is required (rich text)\nimport DOMPurify from 'dompurify';\nelement.innerHTML = DOMPurify.sanitize(userInput, {\n  ALLOWED_TAGS: ['b', 'i', 'em', 'strong', 'a'],\n  ALLOWED_ATTR: ['href'],\n});"),
  ("Security","CORS","Intermediate","Cross-Origin Resource Sharing — browser security policy","Does CORS protect your API from server-to-server requests?","No. CORS is a browser-enforced policy — browsers respect it, servers don't. A Node.js script or curl ignores CORS headers and can call your API freely. Real protection: auth tokens, rate limiting.","// Server (Express)\napp.use(cors({\n  origin: ['https://devquiz.app', 'http://localhost:5173'],\n  credentials: true, // allow cookies\n  methods: ['GET','POST','PUT','DELETE'],\n  allowedHeaders: ['Content-Type', 'Authorization'],\n}));\n// Preflight (OPTIONS) is handled automatically by cors()"),
  ("Async","Promise combinators","Advanced","all, allSettled, any, race","When do you use Promise.any vs Promise.race?","race: resolves/rejects with first settled (either fulfilled or rejected). any: resolves with first FULFILLED, ignores rejections, only rejects if ALL reject.","// Race: first settled wins (including errors)\nconst result = await Promise.race([fetch(primary), timeout(5000)]);\n\n// Any: first success wins, ignores failures\nconst fastest = await Promise.any([fetchFromCDN1(url), fetchFromCDN2(url)]);\n\n// All: all must succeed\nconst [user, posts] = await Promise.all([fetchUser(id), fetchPosts(id)]);\n\n// AllSettled: wait for all, get status of each\nconst results = await Promise.allSettled([p1, p2, p3]);"),
]

