REACT_EXTRA = [
  ("Testing","React Testing Library","Intermediate","Test components as users interact — not implementation","What is the guiding principle of RTL?","Test behaviour, not implementation. Query by accessible role/text/label (as a user would), not by class names or component internals. Encourages accessible code.","import { render, screen, fireEvent, waitFor } from '@testing-library/react';\ntest('submits form with user data', async () => {\n  render(<LoginForm onLogin={mockFn} />);\n  fireEvent.change(screen.getByLabelText('Email'), { target: { value: 'a@b.com' } });\n  fireEvent.change(screen.getByLabelText('Password'), { target: { value: 'pass' } });\n  fireEvent.click(screen.getByRole('button', { name: /sign in/i }));\n  await waitFor(() => expect(mockFn).toHaveBeenCalledWith('a@b.com', 'pass'));\n});"),
  ("Testing","Mocking in React tests","Intermediate","Mock API calls, modules, timers","How do you mock fetch in React tests?","Use global.fetch = jest.fn() or MSW (Mock Service Worker) — MSW intercepts at network level, works in both tests and browser.","// MSW setup\nimport { http, HttpResponse } from 'msw';\nimport { setupServer } from 'msw/node';\nconst server = setupServer(\n  http.get('/api/user', () => HttpResponse.json({ name: 'Alice' })),\n);\nbeforeAll(() => server.listen());\nafterEach(() => server.resetHandlers());\nafterAll(() => server.close());"),
  ("State","React Query / TanStack Query","Intermediate","Server state management: caching, refetching, mutations","What does staleTime control?","How long data is considered fresh. During staleTime, no refetch happens. After staleTime, data is 'stale' — still shown but refetched in background on window focus or remount.","import { useQuery, useMutation, useQueryClient } from '@tanstack/react-query';\nconst { data, isLoading } = useQuery({\n  queryKey: ['user', userId],\n  queryFn:  () => fetchUser(userId),\n  staleTime: 60_000, // fresh for 1 min\n  gcTime:    5 * 60_000, // removed from cache after 5 min\n});\nconst qc = useQueryClient();\nconst mut = useMutation({ mutationFn: updateUser, onSuccess: () => qc.invalidateQueries(['user']) });"),
  ("State","Jotai & Recoil","Advanced","Atomic state management","What is the advantage of atomic state over a single store?","Atoms are independent — components only subscribe to atoms they use. No need for selectors to prevent re-renders. Easy to derive state with computed atoms.","import { atom, useAtom } from 'jotai';\nconst countAtom  = atom(0);\nconst doubleAtom = atom(get => get(countAtom) * 2); // derived\n\nfunction Counter() {\n  const [count, setCount] = useAtom(countAtom);\n  const [double] = useAtom(doubleAtom);\n  return <button onClick={() => setCount(c => c + 1)}>{count} x2={double}</button>;\n}"),
  ("Forms","React Hook Form","Intermediate","Performant forms with minimal re-renders","Why is RHF faster than controlled inputs?","Uncontrolled by default — uses refs, not state. Only re-renders on actual errors or on submit. Formik re-renders on every keystroke (controlled inputs).","import { useForm } from 'react-hook-form';\nimport { zodResolver } from '@hookform/resolvers/zod';\nconst { register, handleSubmit, formState: { errors } } = useForm({\n  resolver: zodResolver(schema),\n});\n<form onSubmit={handleSubmit(onSubmit)}>\n  <input {...register('email')} />\n  {errors.email && <span>{errors.email.message}</span>}\n  <button type='submit'>Submit</button>\n</form>"),
  ("Patterns","useOptimistic (React 19)","Advanced","Optimistic UI updates during async transitions","What happens when the server call fails with useOptimistic?","The optimistic state is automatically reverted to the previous value. React handles the rollback when the action's Promise rejects.","import { useOptimistic, useTransition } from 'react';\nconst [optimisticLikes, addOptimisticLike] = useOptimistic(\n  likes,\n  (state, newLike) => [...state, newLike]\n);\nasync function handleLike() {\n  addOptimisticLike({ id: 'temp', userId }); // immediate UI update\n  await likePost(postId); // actual server call\n  // On failure: auto-reverts optimisticLikes\n}"),
  ("React 19","use() hook","Advanced","Read resources (Promises, Context) in render","What makes use() different from useContext and await?","use() can be called conditionally (unlike other hooks). Works with Promises — suspends the component until Promise resolves. Works with Context — same as useContext but callable anywhere.","import { use } from 'react';\n// Read context conditionally\nif (darkMode) {\n  const theme = use(ThemeContext); // OK -- use() is conditional-safe\n}\n// Unwrap promise (suspends until resolved)\nfunction UserProfile({ userPromise }) {\n  const user = use(userPromise); // suspends, then renders\n  return <div>{user.name}</div>;\n}"),
  ("Accessibility","React Accessibility","Intermediate","aria-* props, role, keyboard navigation, focus management","How do you implement a focus trap in a modal?","On modal open: save last focused element, move focus into modal. Intercept Tab/Shift+Tab to cycle through focusable elements inside modal. On close: restore focus to saved element.","function useFocusTrap(ref: RefObject<HTMLElement>, active: boolean) {\n  useEffect(() => {\n    if (!active) return;\n    const el = ref.current;\n    const focusable = el?.querySelectorAll('button,input,[tabindex]:not([tabindex=\"-1\"])');\n    const first = focusable?.[0] as HTMLElement;\n    const last  = focusable?.[focusable.length-1] as HTMLElement;\n    first?.focus();\n    const handleTab = (e: KeyboardEvent) => {\n      if (e.key !== 'Tab') return;\n      if (e.shiftKey ? document.activeElement === first : document.activeElement === last) {\n        e.preventDefault();\n        (e.shiftKey ? last : first).focus();\n      }\n    };\n    el?.addEventListener('keydown', handleTab);\n    return () => el?.removeEventListener('keydown', handleTab);\n  }, [active]);\n}"),
  ("Internals","Fiber architecture","Advanced","React's internal reconciliation engine","What problem did Fiber solve over the old stack reconciler?","Old reconciler: synchronous, recursive — once started, couldn't be interrupted. Fiber: work broken into units, interruptible, prioritizable. Enables concurrent features (useTransition, Suspense streaming).","// Fiber = linked list of work units\n// Each component = a fiber node with:\n// - type (function/class/element)\n// - key\n// - stateNode (DOM/class instance)\n// - child/sibling/return (tree pointers)\n// - pendingProps / memoizedProps\n// - pendingState\n// - effectTag (insert/update/delete)\n// Work loop can yield between fiber units"),
  ("Tricky","React 18 root API","Tricky","createRoot vs ReactDOM.render","Why must you use createRoot for React 18 features?","createRoot enables concurrent mode — all React 18 features (automatic batching, useTransition, Suspense streaming) require it. ReactDOM.render uses legacy mode — no concurrent features.","// React 18\nimport { createRoot } from 'react-dom/client';\nconst root = createRoot(document.getElementById('root'));\nroot.render(<App />);\n// Hydration (SSR)\nimport { hydrateRoot } from 'react-dom/client';\nconst root = hydrateRoot(document.getElementById('root'), <App />);"),
]

