NEXT_EXTRA = [
  ("Auth","NextAuth / Auth.js","Intermediate","Authentication framework for Next.js","How does Auth.js handle session storage?","By default: JWTs (stateless — no DB needed). Can switch to database sessions (Prisma/Drizzle adapter) for revoking sessions server-side. JWT session stored in HTTP-only cookie.","// app/api/auth/[...nextauth]/route.ts\nimport NextAuth from 'next-auth';\nimport GitHub from 'next-auth/providers/github';\nconst { handlers, auth } = NextAuth({\n  providers: [GitHub],\n  callbacks: {\n    session: ({ session, token }) => ({ ...session, userId: token.sub }),\n  },\n});\nexport const { GET, POST } = handlers;\n// In Server Component:\nconst session = await auth();"),
  ("Auth","Protecting routes","Intermediate","Middleware-based auth guards","How do you protect pages in App Router without a HOC?","Use middleware (edge runtime) to check token and redirect. For server components, call auth() at the top and redirect(). For client components, useSession() from next-auth/react.","// middleware.ts\nexport { auth as middleware } from '@/auth';\nexport const config = { matcher: ['/dashboard/:path*', '/api/user/:path*'] };\n// Server Component auth check\nimport { auth } from '@/auth';\nimport { redirect } from 'next/navigation';\nasync function DashboardPage() {\n  const session = await auth();\n  if (!session) redirect('/login');\n  return <Dashboard user={session.user} />;\n}"),
  ("Testing","Next.js Testing","Intermediate","Jest + React Testing Library for App Router","How do you test Server Components?","Server Components are async functions — render them and await. For components with fetch, mock global.fetch. Use next/jest config for transforms.","// jest.config.ts\nconst config = require('next/jest');\nmodule.exports = config({ dir: './' })({\n  testEnvironment: 'jsdom',\n});\n// Test Server Component\nit('renders posts', async () => {\n  global.fetch = jest.fn().mockResolvedValue({\n    ok: true, json: async () => [{ id: 1, title: 'Post' }]\n  });\n  const jsx = await PostsList();\n  const { getByText } = render(jsx);\n  expect(getByText('Post')).toBeTruthy();\n});"),
  ("Deployment","Vercel deployment","Basic","Deploying Next.js to Vercel","What is the difference between Vercel Edge and Serverless functions?","Serverless: full Node.js runtime, runs per-region, cold starts. Edge: V8 isolates, runs globally close to user, instant cold start, no Node.js APIs. Edge is faster for auth middleware and A/B testing; Serverless for DB queries.","// Use Edge runtime for fast middleware\nexport const runtime = 'edge'; // in route.ts or page.tsx\n// Vercel-specific features\n// ISR: fetch with revalidate\n// Edge Config: ultra-low-latency key-value\nimport { get } from '@vercel/edge-config';\nconst featureFlag = await get('enableNewUI');"),
  ("i18n","Internationalisation","Intermediate","Multiple language support in Next.js","How do you implement i18n in App Router?","Use locale-based routing: app/[locale]/layout.tsx. Detect preferred locale in middleware. next-intl or next-i18next libraries handle message loading and formatting.","// middleware.ts -- detect and redirect to locale\nimport { match } from '@formatjs/intl-localematcher';\nexport function middleware(req) {\n  const locale = match(acceptedLanguages, ['en','hi','es'], 'en');\n  req.nextUrl.pathname = `/${locale}${req.nextUrl.pathname}`;\n  return NextResponse.redirect(req.nextUrl);\n}\n// app/[locale]/layout.tsx\nexport default async function Layout({ children, params }) {\n  const { locale } = await params;\n  const messages = await import(`../../messages/${locale}.json`);\n  return <NextIntlClientProvider locale={locale} messages={messages.default}>{children}</NextIntlClientProvider>;\n}"),
  ("Error Handling","error.tsx & global-error.tsx","Intermediate","Error boundaries in App Router","What is the difference between error.tsx and global-error.tsx?","error.tsx: handles errors in the segment — layout still renders. global-error.tsx: handles errors in root layout — must include <html>/<body>, replaces entire page.","// app/dashboard/error.tsx\n'use client';\nexport default function Error({ error, reset }: { error: Error; reset: () => void }) {\n  return (\n    <div>\n      <h2>Dashboard error: {error.message}</h2>\n      <button onClick={reset}>Try again</button>\n    </div>\n  );\n}\n// app/global-error.tsx\n'use client';\nexport default function GlobalError({ error, reset }) {\n  return <html><body><h1>Fatal error</h1><button onClick={reset}>Reload</button></body></html>;\n}"),
  ("Security","Next.js Security headers","Advanced","Set security headers via next.config","What is Content-Security-Policy and why is it important?","CSP tells browser which sources are allowed for scripts, styles, images, etc. Prevents XSS — even if attacker injects a <script>, CSP blocks execution if src not whitelisted.","// next.config.ts\nconst securityHeaders = [\n  { key: 'X-Frame-Options', value: 'DENY' },\n  { key: 'X-Content-Type-Options', value: 'nosniff' },\n  { key: 'Referrer-Policy', value: 'strict-origin-when-cross-origin' },\n  { key: 'Content-Security-Policy',\n    value: \"default-src 'self'; script-src 'self' 'nonce-{nonce}'\" },\n];\nasync headers() { return [{ source: '/(.*)', headers: securityHeaders }]; }"),
  ("Performance","Bundle analysis","Intermediate","Analyse and reduce Next.js bundle size","How do you use @next/bundle-analyzer?","Install, wrap next.config with withBundleAnalyzer, set ANALYZE=true at build time. Opens a treemap of your client + server bundles — identify large dependencies.","npm i @next/bundle-analyzer\n// next.config.ts\nconst withAnalyzer = require('@next/bundle-analyzer')({\n  enabled: process.env.ANALYZE === 'true',\n});\nmodule.exports = withAnalyzer(nextConfig);\n// Run\nANALYZE=true npm run build"),
]

