TS_EXTRA = [
  ("Types","Zod runtime validation","Intermediate","Schema validation that derives TypeScript types","How does Zod differ from TypeScript types?","TS types are compile-time only — erased at runtime. Zod validates at runtime AND infers TS types. Use for API responses, form data, env variables.","import { z } from 'zod';\nconst UserSchema = z.object({\n  id:    z.string().uuid(),\n  name:  z.string().min(1).max(100),\n  email: z.string().email(),\n  age:   z.number().int().min(0).optional(),\n});\ntype User = z.infer<typeof UserSchema>; // TS type from schema\nconst result = UserSchema.safeParse(apiResponse);\nif (result.success) { const user: User = result.data; }"),
  ("Types","Type narrowing patterns","Advanced","instanceof, typeof, in, discriminated unions, assertion functions","What is the in operator used for in TS narrowing?","'prop' in obj narrows to types that have that property. Works for distinguishing union members without a discriminant field.","function handleResponse(res: SuccessResponse | ErrorResponse) {\n  if ('data' in res) {\n    console.log(res.data); // SuccessResponse\n  } else {\n    console.error(res.error); // ErrorResponse\n  }\n}\n// instanceof narrowing\nfunction handle(e: unknown) {\n  if (e instanceof ValidationError) showValidation(e.fields);\n  else if (e instanceof NetworkError) showRetry();\n  else throw e;\n}"),
  ("Patterns","Builder pattern with types","Advanced","Fluent API for constructing complex objects type-safely","How do you enforce required fields at the type level with Builder?","Use phantom types — track which fields have been set as type parameters. The build() method is only available when all required types are set.","class QueryBuilder<TTable extends string = never, TFields extends string = never> {\n  #table = '';\n  #fields: string[] = [];\n  from<T extends string>(table: T): QueryBuilder<T, TFields> {\n    this.#table = table;\n    return this as any;\n  }\n  select<F extends string>(...fields: F[]): QueryBuilder<TTable, F> {\n    this.#fields = fields;\n    return this as any;\n  }\n  build(this: QueryBuilder<string, string>) {\n    return `SELECT ${this.#fields.join(',')} FROM ${this.#table}`;\n  }\n}\nnew QueryBuilder().from('users').select('id','name').build();"),
  ("Config","Path aliases","Basic","Resolve @/ imports to src/ directory","How do you set up path aliases in TS + Vite?","Two places: tsconfig.json paths (for TS type checking) and vite.config.ts resolve.alias (for bundler resolution). Both required.","// tsconfig.json\n{ \"compilerOptions\": { \"paths\": { \"@/*\": [\"./src/*\"] } } }\n// vite.config.ts\nimport path from 'path';\nexport default defineConfig({\n  resolve: { alias: { '@': path.resolve(__dirname, 'src') } },\n});\n// Usage\nimport { Button } from '@/components/Button';"),
  ("Types","Discriminated unions with exhaustive check","Tricky","Ensure all union cases are handled","Why combine discriminated unions with never?","TypeScript will error at the never assignment if a new union member is added and not handled in the switch. Automated exhaustiveness checking at compile time.","type Notification =\n  | { type: 'email'; to: string }\n  | { type: 'sms';   phone: string }\n  | { type: 'push';  deviceId: string };\nfunction send(n: Notification) {\n  switch (n.type) {\n    case 'email': sendEmail(n.to); break;\n    case 'sms':   sendSMS(n.phone); break;\n    case 'push':  sendPush(n.deviceId); break;\n    default:\n      const _: never = n; // compile error if new type added\n  }\n}"),
]

