HTML_EXTRA = [
  ("Semantics","time element","Basic","Machine-readable date/time with human text","Why use <time> instead of plain text for dates?","Machine-parseable datetime attribute enables calendar apps, search engines, screen readers, and microformats to extract dates reliably.","<time datetime='2024-12-25'>Christmas Day</time>\n<time datetime='2024-12-25T09:00:00Z'>Dec 25 at 9am UTC</time>"),
  ("Semantics","address element","Basic","Contact information for nearest article/body ancestor","Is <address> for postal addresses?","Not necessarily — it's for contact info of the author/owner of the nearest article or body. Physical address is one use case but also: email, phone, social.","<footer>\n  <address>\n    Written by <a href='mailto:author@dev.com'>Author</a>.\n    Visit at <a href='https://devquiz.app'>DevQuiz</a>.\n  </address>\n</footer>"),
  ("Semantics","srcset & sizes","Intermediate","Responsive images with multiple resolutions","What is the difference between srcset with w descriptors vs x descriptors?","w (width descriptor): browser picks based on layout size × device DPR. x (pixel density): only considers device DPR, not layout. Use w descriptors with sizes for full responsive control.","<img\n  src='img-400.jpg'\n  srcset='img-400.jpg 400w, img-800.jpg 800w, img-1200.jpg 1200w'\n  sizes='(max-width: 600px) 100vw, (max-width: 1200px) 50vw, 33vw'\n  alt='Responsive image'\n  loading='lazy'\n  decoding='async'\n>"),
  ("Performance","loading=lazy","Basic","Native browser lazy loading for images and iframes","Does loading=lazy work on all browsers?","Supported in all modern browsers (Chrome 76+, Firefox 75+, Safari 15.4+). Add a JS polyfill or use Intersection Observer for older Safari. Always set explicit width/height to prevent CLS.","<img src='photo.jpg' alt='...' loading='lazy' decoding='async'\n  width='800' height='600'>\n<iframe src='video-embed.html' loading='lazy'></iframe>"),
  ("Tricky","contenteditable pitfalls","Tricky","Browser differences in contenteditable behaviour","What HTML does Enter insert in contenteditable across browsers?","Chrome: <div>. Firefox: <br>. Safari: <br> or <div>. Use execCommand (deprecated) or intercept keydown and normalise. Better: use a rich text library (Tiptap, Slate, Quill).","// Normalise Enter to paragraph\nel.addEventListener('keydown', e => {\n  if (e.key === 'Enter') {\n    e.preventDefault();\n    document.execCommand('insertLineBreak'); // deprecated but works\n    // Or: insert a <p> programmatically\n  }\n});"),
]

