CSS_EXTRA = [
  ("Modern CSS","View Transitions API","Advanced","Animated page transitions with CSS — no JS framework","What is the View Transitions API?","Browser-native page transition animations. Capture before/after states, animate between them with CSS. Works for SPA navigation and (Chrome 126+) cross-document navigation.","// Trigger transition\ndocument.startViewTransition(() => {\n  updateDOM(); // synchronous DOM update\n});\n/* CSS */\n::view-transition-old(root) { animation: slide-out 0.3s ease; }\n::view-transition-new(root) { animation: slide-in 0.3s ease; }\n/* Named transitions */\n.hero { view-transition-name: hero; }"),
  ("Modern CSS","@layer with Tailwind","Advanced","Cascade layers for utility-first CSS control","How do you prevent Tailwind utilities from losing to component CSS?","Wrap base/component styles in lower-priority layers. Tailwind v4 uses @layer natively.","/* Ensure utilities always win */\n@layer base, components, utilities;\n@layer base { body { font-family: sans-serif; } }\n@layer components {\n  .btn { padding: 0.5rem 1rem; border-radius: 0.5rem; }\n}\n/* Tailwind utilities are in @layer utilities -- always override */"),
  ("Modern CSS","color-mix() & oklch","Advanced","Modern CSS color functions","Why use oklch over hsl?","oklch (lightness, chroma, hue) is perceptually uniform — same numeric lightness means same perceived brightness across hues. HSL is not perceptually uniform — blue at 50% L looks darker than yellow at 50% L.","  :root {\n  --primary: oklch(55% 0.2 264); /* indigo */\n  /* Generate tints automatically */\n  --primary-light: oklch(from var(--primary) calc(l + 20%) c h);\n  --primary-dark:  oklch(from var(--primary) calc(l - 20%) c h);\n}\n/* Mix colors */\n.overlay { background: color-mix(in oklch, #6366F1 70%, transparent); }"),
  ("Modern CSS","aspect-ratio","Basic","Maintain element proportions without padding hacks","What did we use before aspect-ratio?","Padding-top hack: padding-top: 56.25% (for 16:9) on a relative container with absolute positioned content. aspect-ratio eliminates this completely.","/* 16:9 video container */\n.video-wrapper { aspect-ratio: 16 / 9; width: 100%; }\n/* Square avatar */\n.avatar { width: 3rem; aspect-ratio: 1; border-radius: 50%; }\n/* Intrinsic if content taller */\n.card { aspect-ratio: 4 / 3 auto; }"),
  ("Modern CSS","CSS Anchoring","Advanced","Position elements relative to another element (CSS Anchor Positioning)","What problem does CSS Anchor Positioning solve?","Positioning tooltips/popovers relative to their trigger — previously required JS to calculate coordinates. Now purely declarative CSS.","/* Chrome 125+ */\n.trigger { anchor-name: --btn; }\n.tooltip {\n  position: absolute;\n  position-anchor: --btn;\n  bottom: calc(anchor(top) + 8px);\n  left: anchor(center);\n  transform: translateX(-50%);\n}"),
]
